<script setup lang="ts">
import AppLayout from '@/layouts/AppLayout.vue'
import { type BreadcrumbItem } from '@/types'
import { Head, Link, useForm } from '@inertiajs/vue3'
import { ArrowLeft, LockKeyhole, Save, UserCog } from 'lucide-vue-next'
import { route } from 'ziggy-js'

const props = defineProps<{ user: { id: number; name: string; email: string }; roles: string[]; userRoles: string[] }>()
const breadcrumbs: BreadcrumbItem[] = [{ title: 'Edit user', href: '/users' }]
const form = useForm({ name: props.user.name, email: props.user.email, password: '', roles: props.userRoles ?? [] })
</script>

<template>
    <Head title="Edit User" />
    <AppLayout :breadcrumbs="breadcrumbs"><main class="mx-auto max-w-4xl p-4 sm:p-6"><Link :href="route('users.index')" class="inline-flex items-center gap-2 text-sm font-medium text-slate-600 hover:text-blue-600 dark:text-slate-300"><ArrowLeft class="h-4 w-4" /> Back to users</Link><form class="mt-5 overflow-hidden rounded-2xl border border-slate-200 bg-slate-50 shadow-sm dark:border-slate-700 dark:bg-slate-950" @submit.prevent="form.put(route('users.update', props.user.id))"><div class="border-b border-slate-200 bg-white p-6 dark:border-slate-700 dark:bg-slate-900"><div class="flex items-center gap-4"><div class="rounded-xl bg-amber-100 p-3 text-amber-700 dark:bg-amber-950"><UserCog class="h-6 w-6" /></div><div><h1 class="text-xl font-bold text-slate-900 dark:text-white">Edit user</h1><p class="text-sm text-slate-500">Update account details or assigned roles.</p></div></div></div><div class="grid gap-6 p-6 lg:grid-cols-2"><section class="space-y-5"><div><label class="text-sm font-medium">Full name</label><input v-model="form.name" class="mt-2 w-full rounded-xl border border-slate-300 bg-white px-3 py-2.5 dark:border-slate-600 dark:bg-slate-800" /><p v-if="form.errors.name" class="mt-1 text-sm text-red-600">{{ form.errors.name }}</p></div><div><label class="text-sm font-medium">Email address</label><input v-model="form.email" type="email" class="mt-2 w-full rounded-xl border border-slate-300 bg-white px-3 py-2.5 dark:border-slate-600 dark:bg-slate-800" /><p v-if="form.errors.email" class="mt-1 text-sm text-red-600">{{ form.errors.email }}</p></div><div><label class="text-sm font-medium">New password</label><div class="relative mt-2"><LockKeyhole class="absolute left-3 top-3 h-4 w-4 text-slate-400" /><input v-model="form.password" type="password" class="w-full rounded-xl border border-slate-300 bg-white py-2.5 pl-10 pr-3 dark:border-slate-600 dark:bg-slate-800" placeholder="Enter a new password" /></div><p class="mt-1 text-xs text-slate-500">Leave blank to keep the current password.</p><p v-if="form.errors.password" class="mt-1 text-sm text-red-600">{{ form.errors.password }}</p></div></section><section><h2 class="font-semibold text-slate-900 dark:text-white">Assigned roles</h2><p class="text-sm text-slate-500">{{ form.roles.length }} roles selected</p><div class="mt-4 space-y-2"><label v-for="role in props.roles" :key="role" class="flex cursor-pointer items-center gap-3 rounded-xl border border-slate-200 bg-white p-3 hover:border-blue-300 dark:border-slate-700 dark:bg-slate-900"><input v-model="form.roles" :value="role" type="checkbox" class="h-4 w-4 rounded border-slate-300 text-blue-600" /><span class="font-medium capitalize text-slate-700 dark:text-slate-200">{{ role }}</span></label></div></section></div><div class="flex justify-end gap-3 border-t border-slate-200 bg-white p-4 dark:border-slate-700 dark:bg-slate-900"><Link :href="route('users.index')" class="rounded-lg px-4 py-2 text-sm font-semibold text-slate-600 hover:bg-slate-100">Cancel</Link><button :disabled="form.processing" class="inline-flex items-center gap-2 rounded-lg bg-blue-600 px-4 py-2 text-sm font-semibold text-white hover:bg-blue-700 disabled:opacity-50"><Save class="h-4 w-4" /> Save changes</button></div></form></main></AppLayout>
